  ('social-worker-moex-05640', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於連續理論（continuity theory）的內涵，下列那一項正確？', '["為了回應社會互動理論所遭受到的批評", "個人的人格差異被視為適應老年生活能力之主要影響因素", "個人沿用短時間的因應風格來維持現狀", "之前在生活中積極活躍的個人，到了老年期就以休息為主，不再參加各種活動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05641', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '混合家庭的成員必須適應許多不同的情況，亦可能會產生一些適應上的困難，然而下列那一項不是混合 家庭的迷思？', '["邪惡的繼母會虐待孩子", "混合家庭從形成的那一刻起所有家人就會彼此相愛", "混合家庭是社會主流，家庭成員間互動關係複雜", "混合家庭裡，繼子或繼女的地位比不上親生孩子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05642', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在兒童行為管理上，懲罰常是最不願意使用的手段，雖可維持紀律但也造成負面效果，試問那一項不是 潛在負面的效果？', '["懲罰引起兒童負面情緒反應", "懲罰示範了攻擊性行為", "懲罰激勵兒童努力行善動機與意願", "懲罰僅讓兒童知道什麼是不該做的，卻無法明確指出應該怎麼做"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05643', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '氣質（temperament）可用來說明個人的心理與情緒本質及對他人與周遭環境的回應型態，下列那一項不 是嬰兒氣質的面向？', '["情緒性", "活動力", "社會力", "訓練力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05644', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Hyde（2009）提及文化女性主義，其內涵陳述，下列那一項是正確的？', '["主張女性獨特性、不同於男性的特質", "主張女性與男性有相同的機會與權利", "主張根除父權與改變生活方式", "主張性別與性都是個人修正其男子氣概或女性化的表現以符合目的之結果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05645', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '生命歷程理論先驅葛蘭･艾爾樂（Glen H. Elder Jr.）認為人類早期的生活經驗與日後的發展軌跡有顯著的 關聯，下列那一項基本概念敘述錯誤？', '["世代是指一群人出生於某一特定歷史時期，具有不同的年齡與生活模式下歷練不特定社會變遷事件", "軌跡是指長期的身心發展變化模式", "轉捩點是指生活事件的發生造成人類個體生命歷程軌跡中長期性角色任務的轉換", "生命事件是指重大生活事件引發之狀況可能導致長期嚴重性的生涯中斷，改變不同個體的生命歷程， 使人類呈現顯著的差異性行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05646', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '以自我為中心，傾向於以偏概全產生許多認知上錯誤，在皮亞傑（Piaget）認知發展階段，屬於下列那一 個階段？', '["感覺運動期（sensorimotor stage）", "運思前期（preoperational stage）", "具體運思期（concrete operations stage）", "形式運思期（formal operations stage）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05647', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '艾瑞克森（Erikson）指出，人類發展階段中個體發展出「我是誰」及「我的人生將往何處去」的認同感， 試問是屬於下列那一項生命階段？', '["兒童中期（6至10歲）", "青少年期（11至20歲）", "青壯年期（21至40歲）", "中年期（41至65歲）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05648', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '艾瑞克森（Erikson）的心理社會發展階段中，其心理社會發展階段中的「親密vs疏離」是屬於下列那一 項生命階段？', '["兒童早期（3至5歲）", "兒童中期（6至10歲）", "青少年期（11至20歲）", "青壯年期（21至40歲）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05649', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依附理論學者安斯渥斯（Mary Ainsworth）和其同事建構的依附關係中指出，嬰兒不願意探索遊戲室並一 直黏著母親不放，當母親離開房間時，嬰兒不斷的哭泣；當母親返回時，嬰兒會尋求母親的安慰，但仍 繼續哭泣，試問是屬於下列那一類型依附關係？', '["衝突型依附", "安全型依附", "迴避型依附", "焦慮型依附"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
